sql:
SELECT COUNT(DISTINCT model_id) AS total_models_updated
FROM model_updates
WHERE updated_at > '2023-01-01 00:00:00';

external_knowledge:
- 'SVM' stands for Support Vector Machine, a popular machine learning algorithm;
- 'active' status implies that the model is currently in use or available for use;
- 'approved' updates are those that have been officially reviewed and accepted into the model;
- Non-null update dates refer to the fact that there was at least one recorded date for the model update.

sql:
SELECT DISTINCT users.user_id, users.name
FROM users
JOIN ratings ON users.user_id = ratings.user_id;

SELECT model_id, disparate_impact 
FROM model_performance
WHERE performance_id BETWEEN 1000 AND 10000;
